let MeestAddress=function(data){let inputContainer=data.inputContainer||"tr",separateContainer=data.separateContainer||false,deliveryType=data.deliveryType?{block:data.deliveryType.block,branch:data.deliveryType.branch,address:data.deliveryType.address}:null,country={code:data.country.code,id:data.country.id,text:data.country.text},region={text:data.region.text},city={id:data.city.id,text:data.city.text},street={id:data.street.id,text:data.street.text},building=data.building,flat=data.flat,postcode={container:data.postcode.container,text:data.postcode.text},branch=data.branch?{id:data.branch.id,text:data.branch.text}:null;return{initCountry:function(country){return country.select2({minimumInputLength:null,ajax:{type:"POST",url:meest.ajaxUrl,delay:600,dataType:"json",data:params=>({action:meest.actions.get_country,text:params.term}),processResults:data=>({results:data.map(item=>({id:item.id,text:item.text,code:item.code}))})}})},initCity:function(city,country){if(country.val()===meest.country_id.ua){return city.select2({ajax:{type:"POST",url:meest.ajaxUrl,delay:600,dataType:"json",data:params=>({action:meest.actions.get_city,country:country.val(),text:params.term}),processResults:data=>({results:data.map(item=>({id:item.id,text:item.text,region:item.region,city:item.city}))})}})}},initStreet:function(street,city,country){if(country.val()===meest.country_id.ua){return street.select2({ajax:{type:"POST",url:meest.ajaxUrl,delay:600,dataType:"json",data:params=>({action:meest.actions.get_street,city:city.val(),text:params.term}),processResults:data=>({results:data.map(item=>({id:item.id,text:item.text}))})}})}},initBranch:function(branch,city){return branch.select2({ajax:{type:"POST",url:meest.ajaxUrl,delay:600,dataType:"json",data:params=>({action:meest.actions.get_branch,city:city.val(),text:params.term}),processResults:data=>({results:data.map(item=>({id:item.id,text:item.text,description:item.description}))})},templateResult:function(option){return jQuery("<strong>"+option.text+"</strong>"+(option.description?"<div><small>"+option.description+"</small</div>":""))}})},init:function(){let self=this;deliveryType&&deliveryType.block.change(function(){if(this.value==="branch"){branch.id.removeAttr("disabled").closest(inputContainer).show();street.id.closest(inputContainer).hide();building.closest(inputContainer).hide();flat.closest(inputContainer).hide();self.initBranch(branch.id,city.id).on("select2:select",e=>branch.text.val(e.params.data.text))}else{branch.id.attr("disabled","disabled").closest(inputContainer).hide();street.id.removeAttr("disabled").closest(inputContainer).show();building.removeAttr("disabled").closest(inputContainer).show();flat.removeAttr("disabled").closest(inputContainer).show();self.initStreet(street.id,city.id,country.id).on("select2:select",e=>street.text.val(e.params.data.text))}});self.initCountry(country.id).on("select2:select",function(e){if(e.params){country.code&&country.code.val(e.params.data.code);country.text.val(e.params.data.text)}if(country.id.val()===meest.country_id.ua){region.text.closest(inputContainer).hide();deliveryType&&deliveryType.block.closest(inputContainer).show();city.id.removeAttr("disabled").closest(inputContainer).show();postcode.text.attr("disabled","disabled").closest(postcode.container).hide();if(separateContainer){city.text.closest(inputContainer).hide();street.text.closest(inputContainer).hide()}else{city.text.hide();street.text.hide()}self.initCity(city.id,country.id).on("select2:select",e=>{city.text.val(e.params.data.city);street.id.empty().trigger("change");street.text.val("");branch.id.empty().trigger("change");branch.text.val("")});if(deliveryType&&deliveryType.branch.is(":checked")){branch.id.removeAttr("disabled").closest(inputContainer).show();street.id.attr("disabled","disabled").closest(inputContainer).hide();building.attr("disabled","disabled").closest(inputContainer).hide();flat.attr("disabled","disabled").closest(inputContainer).hide();self.initBranch(branch.id,city.id).on("select2:select",e=>branch.text.val(e.params.data.text))}else{branch&&branch.id.attr("disabled","disabled").closest(inputContainer).hide();street.id.removeAttr("disabled").closest(inputContainer).show();building.removeAttr("disabled").closest(inputContainer).show();flat.removeAttr("disabled").closest(inputContainer).show();self.initStreet(street.id,city.id,country.id).on("select2:select",e=>street.text.val(e.params.data.text))}}else{branch&&branch.id.attr("disabled","disabled").closest(inputContainer).hide();if(separateContainer){region.text.closest(inputContainer).show();city.id.attr("disabled","disabled").closest(inputContainer).hide();city.text.closest(inputContainer).show();street.id.attr("disabled","disabled").closest(inputContainer).hide();street.text.closest(inputContainer).show()}else{region.text.closest(inputContainer).show();city.id.attr("disabled","disabled").hide().next(".select2-container").hide();city.text.show().closest(inputContainer).show();street.id.attr("disabled","disabled").hide().next(".select2-container").hide();street.text.show().closest(inputContainer).show()}building.removeAttr("disabled").closest(inputContainer).show();flat.removeAttr("disabled").closest(inputContainer).show();postcode.text.removeAttr("disabled").closest(postcode.container).show();deliveryType&&deliveryType.block.closest(inputContainer).hide();deliveryType&&deliveryType.address.prop("checked",true)}}).trigger("select2:select")}}};